app = Flask(__name__)
logging.basicConfig(level=logging.DEBUG)

def log_error(error):
    # Log the error with a traceback for debugging purposes
    app.logger.error(f"An error occurred: {error}", exc_info=True)
    return jsonify({'message': 'An internal error occurred', 'details': str(error)}), 500

@app.errorhandler(Exception)
def handle_exception(e):
    # Handle all exceptions and return a generic error message
    response = log_error(e)
    return response

@app.route('/test')
def test_route():
    # This route is for testing purposes
    raise ValueError('This is a test error')

if __name__ == '__main__':
    app.run(debug=True)

